mapper.select:
select t4.id,t4.name, t4.status ,t4.create_time from (select t1.*,t3.name as label_name from kb_label_category t1 left join kb_category_label t2 on t1.id = t2.ct_id left join kb_model_label t3 on t2.l_id = t3.id where t1.is_deleted = 2 and t3.is_deleted = 2
AND t1.name like concat('%',#{kbLabelCategoryDto.name},'%')
AND t3.name like concat('%',#{kbLabelCategoryDto.labelName},'%')
) t4 group by 1,2,3,4
limit #{map.offset},#{map.rows}
